event eProxyReadReq: (key: int, requester: machine, reqId: int, podId: int);
event eProxyWriteReq: (key: int, value: int, requester: machine, reqId: int, podId: int);
event eProxyReadResp: (reqId: int, key: int, value: int);
event eProxyWriteResp: (reqId: int, key: int, success: bool, value: int);
event eProxyStep;

machine StorageProxy {
    var db: machine;

    var queue: seq[(isWrite: bool, key: int, value: int, caller: machine, reqId: int, podId: int)];
    var busy: bool;

    // Inflight op (valid only when busy == true)
    var inflightIsWrite: bool;
    var inflightKey: int;
    var inflightVal: int;
    var inflightCaller: machine;
    var inflightReqId: int;
    var inflightPodId: int;

    start state Init {
        entry (p: (db: machine)) {
            db = p.db;
            busy = false;
            goto Ready;
        }
    }

    state Ready {
        on eProxyReadReq do (r: (key: int, requester: machine, reqId: int, podId: int)) {
            var op: (isWrite: bool, key: int, value: int, caller: machine, reqId: int, podId: int);
            var pendingCount: int;
            op = (isWrite = false, key = r.key, value = 0, caller = r.requester, reqId = r.reqId, podId = r.podId);
            queue += (sizeof(queue), op);
            pendingCount = sizeof(queue);
            announce eMonitorProxyEnqueue, (key = r.key, podId = r.podId, isWrite = false, pending = pendingCount);
            send this, eProxyStep;
        }

        on eProxyWriteReq do (w: (key: int, value: int, requester: machine, reqId: int, podId: int)) {
            var op: (isWrite: bool, key: int, value: int, caller: machine, reqId: int, podId: int);
            var pendingCount: int;
            op = (isWrite = true, key = w.key, value = w.value, caller = w.requester, reqId = w.reqId, podId = w.podId);
            queue += (sizeof(queue), op);
            pendingCount = sizeof(queue);
            announce eMonitorProxyEnqueue, (key = w.key, podId = w.podId, isWrite = true, pending = pendingCount);
            send this, eProxyStep;
        }

        on eProxyStep do {
            var n: int;
            var idx: int;
            var op: (isWrite: bool, key: int, value: int, caller: machine, reqId: int, podId: int);
            var doHold: bool;

            n = sizeof(queue);

            if (n == 0) {
                // nothing to do
                return;
            }

            if (busy) {
                // Model congestion while there is queued work but link is busy
                announce eMonitorProxyHold, (pending = n);
                // keep stepping until we can forward
                send this, eProxyStep;
                return;
            }

            // Not busy and have queued work: nondeterministically hold or forward one
            doHold = $;
            if (doHold) {
                announce eMonitorProxyHold, (pending = n);
                send this, eProxyStep;
                return;
            }

            // Forward one randomly chosen queued request
            idx = choose(n);
            op = queue[idx];
            // announce forwarding with current pending count
            announce eMonitorProxyForward, (key = op.key, podId = op.podId, isWrite = op.isWrite, pending = n);

            // Pop from queue
            queue -= (idx);

            // Mark inflight
            busy = true;
            inflightIsWrite = op.isWrite;
            inflightKey = op.key;
            inflightVal = op.value;
            inflightCaller = op.caller;
            inflightReqId = op.reqId;
            inflightPodId = op.podId;

            if (op.isWrite) {
                send db, eStorageWrite, (caller = this, key = op.key, value = op.value, podId = op.podId);
            } else {
                send db, eStorageRead, (caller = this, key = op.key, podId = op.podId);
            }
        }

        on eStorageReadResp do (resp: (key: int, value: int)) {
            // Deliver logical response back to cache/pod
            announce eMonitorProxyResponseDelivered, (key = inflightKey, podId = inflightPodId, isWrite = false);
            send inflightCaller, eProxyReadResp, (reqId = inflightReqId, key = resp.key, value = resp.value);

            // Clear inflight and continue
            busy = false;
            send this, eProxyStep;
        }

        on eStorageWriteResp do (resp: (key: int, success: bool, value: int)) {
            // Deliver logical response back to cache/pod
            announce eMonitorProxyResponseDelivered, (key = inflightKey, podId = inflightPodId, isWrite = true);
            send inflightCaller, eProxyWriteResp, (reqId = inflightReqId, key = resp.key, success = resp.success, value = resp.value);

            // Clear inflight and continue
            busy = false;
            send this, eProxyStep;
        }
    }
}

machine CacheNode {
    var proxy: machine;
    var podId: int;

    var nextReqId: int;

    // Track pending client requests by reqId
    var pendingReadClient: map[int, machine];
    var pendingWriteClient: map[int, machine];

    // Optional local cache for future extensibility (not used for serving reads to preserve LSI)
    var localCache: map[int, int];

    start state Init {
        entry (p: (proxy: machine, podId: int)) {
            proxy = p.proxy;
            podId = p.podId;
            nextReqId = 1;
            goto Ready;
        }
    }

    state Ready {
        on eClientRead do (r: (client: machine, key: int)) {
            var reqId: int;
            reqId = nextReqId;
            nextReqId = nextReqId + 1;

            pendingReadClient[reqId] = r.client;

            // Announce request issuance to the proxy monitor
            announce eMonitorProxyRequestIssued, (key = r.key, podId = podId, isWrite = false);
            // Forward to proxy
            send proxy, eProxyReadReq, (key = r.key, requester = this, reqId = reqId, podId = podId);
        }

        on eClientWrite do (w: (client: machine, key: int, value: int)) {
            var reqId: int;
            reqId = nextReqId;
            nextReqId = nextReqId + 1;

            pendingWriteClient[reqId] = w.client;

            // Announce request issuance to the proxy monitor
            announce eMonitorProxyRequestIssued, (key = w.key, podId = podId, isWrite = true);
            // Forward to proxy
            send proxy, eProxyWriteReq, (key = w.key, value = w.value, requester = this, reqId = reqId, podId = podId);
        }

        on eProxyReadResp do (resp: (reqId: int, key: int, value: int)) {
            var c: machine;
            if (resp.reqId in pendingReadClient) {
                c = pendingReadClient[resp.reqId];
                // Always mark fromCache = false to satisfy LSI (we always touch storage for reads)
                send c, eReadResp, (key = resp.key, value = resp.value, fromCache = false);
                pendingReadClient -= (resp.reqId);
                // Optionally remember for future use (not used to serve without storage)
                localCache[resp.key] = resp.value;
            }
        }

        on eProxyWriteResp do (resp: (reqId: int, key: int, success: bool, value: int)) {
            var c: machine;
            if (resp.reqId in pendingWriteClient) {
                c = pendingWriteClient[resp.reqId];
                send c, eWriteResp, (key = resp.key, success = resp.success);
                pendingWriteClient -= (resp.reqId);
                if (resp.success) {
                    localCache[resp.key] = resp.value;
                }
            }
        }
    }
}
